void solve(int CASE)
{
	int n, m, k; cin >> n >> m >> k;
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, m) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
	}

	int timer = 0;
	var vis = vector<bool>(n + 1);
	var dfn = vector<int>(n + 1);
	var dep = vector<int>(n + 1); // 生成树的各个节点的深度
	var par = vector<int>(n + 1);

	var dfs = [&](var dfs, int now, int fa)->void {
		vis[now] = 1;
		dfn[now] = ++timer;
		dep[now] = dep[fa] + 1;
		par[now] = fa;

		for (int to : g[now]) {
			if (to == fa)continue;
			if (vis[to]) {
				if (dfn[to] < dfn[now]) {
					if (dep[now] - dep[to] + 1 >= k + 1) {
						var ans = vector<int>();
						ans.pb(now);
						while (now != to) {
							now = par[now];
							ans.pb(now);
						}
						cout << ans.size() << endl;
						cout << ans << endl;
						exit(0);
					}
				}
			}
			else dfs(dfs, to, now);
		}
		};
	dfs(dfs, 1, 0);
	return;
}
